import { useState } from "react";

const toppings = [
  { emoji: "🍄", price: 40 },
  { emoji: "🧀", price: 45 },
  { emoji: "🌽", price: 30 },
  { emoji: "🫒", price: 35 },
  { emoji: "🧅", price: 20 },
  { emoji: "🌶️", price: 25 },
];

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function addTopping(e) {
    const rect = e.currentTarget.getBoundingClientRect();

    setPizza([
      ...pizza,
      {
        ...selected,
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      },
    ]);
  }

  const total =
    299 + pizza.reduce((sum, topping) => sum + topping.price, 0);

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <p><strong>Total:</strong> ₹{total}</p>



    <p>
		{toppings.map(topping => (
			<button
			key={topping.emoji}
			type="button"
			onClick={() => setSelected(topping)}
			disabled={selected === topping}
			>
			{topping.emoji}
			</button>
		))}
	</p>
	<figure
        onClick={addTopping}
        style={{
        //   position: "relative",
        //   width: 350,
        //   height: 350,
        //   margin: "auto",
        //   border: "2px solid currentColor",
        //   overflow: "hidden",
        //   cursor: "pointer",
        }}
      >
        <img
          src="https://www.shutterstock.com/image-illustration/pizza-no-topping-260nw-2685328587.jpg"
          alt="Pizza"
          width="350"
        />

        {pizza.map((topping, i) => (
          <span
            key={i}
            style={{
              position: "absolute",
              left: topping.x,
              top: topping.y,
              transform: "translate(-50%, -50%)",
              fontSize: "2rem",
            }}
          >
            {topping.emoji}
          </span>
        ))}
      </figure>
    </main>
  );
}
